CREATE TABLE IF NOT EXISTS `club_members` (
  `id` int NOT NULL AUTO_INCREMENT,
  `club_id` varchar(64) NOT NULL,
  `user_id` varchar(64) NOT NULL,
  `display_name` varchar(100) NOT NULL DEFAULT '',
  `chesscom_username` varchar(50),
  `lichess_username` varchar(50),
  `avatar_url` varchar(500),
  `role` varchar(20) NOT NULL DEFAULT 'member',
  `joined_at` timestamp NOT NULL DEFAULT (now()),
  `tournaments_played` int NOT NULL DEFAULT 0,
  `best_finish` int,
  CONSTRAINT `club_members_id` PRIMARY KEY(`id`)
);
CREATE INDEX IF NOT EXISTS `cm_club_idx` ON `club_members` (`club_id`);
CREATE INDEX IF NOT EXISTS `cm_user_idx` ON `club_members` (`user_id`);
CREATE INDEX IF NOT EXISTS `cm_club_user_idx` ON `club_members` (`club_id`, `user_id`);
CREATE INDEX IF NOT EXISTS `clubs_slug_idx` ON `clubs` (`slug`);
CREATE INDEX IF NOT EXISTS `clubs_owner_idx` ON `clubs` (`owner_id`);
CREATE INDEX IF NOT EXISTS `clubs_public_idx` ON `clubs` (`is_public`);

